const now = Date.now()
const day = 24 * 60 * 60 * 1000

function buildAnswers(
  questions: Question[],
  correctCount: number,
): PracticeSession["answers"] {
  const answers: PracticeSession["answers"] = {}
  questions.forEach((q, i) => {
    const isCorrect = i < correctCount
    answers[q.id] = {
      questionId: q.id,
      selectedOptionIds: isCorrect ? q.correctOptionIds : [q.options[0].id],
      isCorrect,
      markedForReview: false,
      skipped: false,
      timeSpentSec: 40 + i * 7,
    }
  })
  return answers
}

