/** Builds a fresh in-progress session from intake input. */
export function createSessionFromIntake(
  exam: string,
  examCode: string,
  focusTopics: string[],
): PracticeSession {
  return {
    id: `s-${Math.random().toString(36).slice(2, 8)}`,
    exam,
    examCode,
    focusTopics,
    createdAt: new Date().toISOString(),
    status: "in-progress",
    questions: SAMPLE_QUESTIONS,
    answers: {},
    currentIndex: 0,
  }
}
